import{_ as a,o,c as s,a2 as r}from"./chunks/framework.BKG_UbFK.js";const m=JSON.parse('{"title":"Segurança","description":"","frontmatter":{},"headers":[],"relativePath":"pt/guide/security.md","filePath":"pt/guide/security.md"}'),d={name:"pt/guide/security.md"};function i(t,e,c,n,l,p){return o(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="seguranca" tabindex="-1">Segurança <a class="header-anchor" href="#seguranca" aria-label="Permalink to &quot;Segurança&quot;">​</a></h1><p>O Clearance passou por uma auditoria de segurança dedicada antes da publicação, mais duas passagens de reforço subsequentes antes do lançamento. Destaques: tetos contra escalonamento de privilégios em todos os caminhos de concessão de permissões (tanto concessões diretas como sincronização ao nível do papel), substituições de contexto com autoridade de negação, um sanitizador de SVG com lista de permissões, um namespace de permissões <code>clearance-*</code> protegido, e diretivas Blade seguras para convidados.</p><h2 id="acesso-ao-painel-e-permissoes-de-escrita-granulares" tabindex="-1">Acesso ao painel e permissões de escrita granulares <a class="header-anchor" href="#acesso-ao-painel-e-permissoes-de-escrita-granulares" aria-label="Permalink to &quot;Acesso ao painel e permissões de escrita granulares&quot;">​</a></h2><p>O acesso de leitura a todo o painel requer a permissão <code>clearance-access</code> (verificada via <code>can()</code>, nunca <code>hasRole()</code>). As operações de escrita em cada secção são controladas por uma permissão dedicada e delegável - todas criadas pelo <code>clearance:install</code> e atribuídas a <code>super_admin</code>:</p><table tabindex="0"><thead><tr><th>Permissão</th><th>Controla</th></tr></thead><tbody><tr><td><code>clearance-permissions-write</code></td><td>Criar / editar / eliminar permissões</td></tr><tr><td><code>clearance-roles-write</code></td><td>Criar / editar / eliminar papéis e as suas atribuições de permissão</td></tr><tr><td><code>clearance-guards-write</code></td><td>Criar / editar / eliminar guards</td></tr><tr><td><code>clearance-settings-write</code></td><td>Editar metadados de exibição, ícones, cores, papel padrão</td></tr><tr><td><code>clearance-users-write</code></td><td>Atribuir / remover papéis para um utilizador específico</td></tr></tbody></table><p>Se uma linha de permissão granular não existir de todo na base de dados (um estado legado anterior à semeadura), a verificação recorre a <code>clearance-access</code> para compatibilidade retroativa.</p><h2 id="namespace-clearance-protegido" tabindex="-1">Namespace <code>clearance-*</code> protegido <a class="header-anchor" href="#namespace-clearance-protegido" aria-label="Permalink to &quot;Namespace `clearance-*` protegido&quot;">​</a></h2><p>As permissões <code>clearance-*</code> são reservadas: não podem ser criadas, renomeadas, eliminadas, ou adicionadas a qualquer papel, exceto através do próprio fluxo de instalação do pacote - mesmo por um ator <code>super_admin</code> para o próprio papel <code>super_admin</code>.</p><h2 id="tetos-contra-escalonamento-de-privilegios" tabindex="-1">Tetos contra escalonamento de privilégios <a class="header-anchor" href="#tetos-contra-escalonamento-de-privilegios" aria-label="Permalink to &quot;Tetos contra escalonamento de privilégios&quot;">​</a></h2><p>Todos os caminhos de concessão de permissões no Clearance aplicam um teto, para que um ator nunca possa conceder mais do que ele próprio detém:</p><ul><li><strong>Papéis-teto</strong> - um papel pode declarar um papel principal cujo conjunto de permissões atua como limite superior. Qualquer permissão em excesso é silenciosamente cortada em <code>RoleService::setParent()</code> e em toda a sincronização de permissões subsequente - sem exceção, sem mensagem de erro. Remover permissões de um papel principal propaga a remoção automaticamente a todos os papéis filho. Ver <a href="/clearance-docs/pt/features/roles.html">Papéis</a> para a API completa de tetos.</li><li><strong>Módulo de Utilizadores</strong> - tanto a atribuição de papéis como as concessões de permissão diretas/de substituição aplicam um teto de privilégio: um ator que não seja <code>super_admin</code> não pode modificar as suas próprias atribuições, nem pode conceder uma permissão que ele próprio não detenha. Ver <a href="/clearance-docs/pt/features/users.html">Utilizadores</a>.</li></ul><h2 id="substituicoes-de-contexto-com-autoridade-de-negacao" tabindex="-1">Substituições de contexto com autoridade de negação <a class="header-anchor" href="#substituicoes-de-contexto-com-autoridade-de-negacao" aria-label="Permalink to &quot;Substituições de contexto com autoridade de negação&quot;">​</a></h2><p>As substituições de permissão por contexto (<code>clr_ctx_overrides</code>) suportam <code>forced_on</code> e <code>forced_off</code>. <code>forced_off</code> ganha sempre - mesmo sobre uma permissão concedida por um papel global. Não existe nenhum caminho que permita a uma concessão de menor precedência sobrepor-se a uma negação explícita. Ver <a href="/clearance-docs/pt/guide/architecture.html#como-funciona-a-resolução">Arquitetura</a> para a ordem de resolução completa.</p><h2 id="sanitizacao-de-svg" tabindex="-1">Sanitização de SVG <a class="header-anchor" href="#sanitizacao-de-svg" aria-label="Permalink to &quot;Sanitização de SVG&quot;">​</a></h2><p>Todo o ícone fornecido pelo utilizador (metadados de exibição de papel/guard no painel de Configurações) passa por um sanitizador com lista de permissões, tanto antes do armazenamento como no momento da renderização - não uma verificação única no upload.</p><h2 id="diretivas-blade-seguras-para-convidados" tabindex="-1">Diretivas Blade seguras para convidados <a class="header-anchor" href="#diretivas-blade-seguras-para-convidados" aria-label="Permalink to &quot;Diretivas Blade seguras para convidados&quot;">​</a></h2><p><code>@canin</code> e <code>@hasrolein</code> resolvem-se ambas de forma segura (devolvem <code>false</code>) para um utilizador convidado - nunca lançam uma exceção.</p><h2 id="o-bypass-da-gate-e-aplicado-a-toda-a-aplicacao" tabindex="-1">O bypass da Gate é aplicado a toda a aplicação <a class="header-anchor" href="#o-bypass-da-gate-e-aplicado-a-toda-a-aplicacao" aria-label="Permalink to &quot;O bypass da Gate é aplicado a toda a aplicação&quot;">​</a></h2><p><code>super_admin_gate_bypass</code> (padrão <code>false</code>) controla se o papel <code>super_admin</code> contorna todas as verificações <code>can()</code> / <code>Gate::allows()</code> / política do Laravel globalmente, através de um hook <code>Gate::before()</code>.</p><div class="warning custom-block"><p class="custom-block-title">Não delimitado ao painel</p><p>Quando ativado, qualquer utilizador que detenha <code>super_admin</code> salta todas as verificações de Gate em toda a aplicação - não apenas as verificações do painel Clearance. Ative-o deliberadamente. Ver <a href="/clearance-docs/pt/features/super-admin.html">Super Admin</a> para o comportamento de deteção de aliases e promoção.</p></div><h2 id="pormenores-relevantes-para-a-seguranca" tabindex="-1">Pormenores relevantes para a segurança <a class="header-anchor" href="#pormenores-relevantes-para-a-seguranca" aria-label="Permalink to &quot;Pormenores relevantes para a segurança&quot;">​</a></h2><ul><li><code>forced_off</code> ganha sempre - mesmo sobre uma permissão concedida por um papel global.</li><li>Um papel-teto apenas corta, nunca concede - definir um papel principal permissivo não concede nada ao filho por si só.</li><li>O bypass da Gate (<code>super_admin_gate_bypass</code>) aplica-se a toda a aplicação, não apenas ao painel.</li><li>O módulo de Utilizadores está desativado por padrão (<code>modules.users = false</code>).</li><li>As permissões <code>clearance-*</code> são intocáveis fora do fluxo de instalação, mesmo para <code>super_admin</code>.</li><li>Execute sempre <code>clearance:install</code>, nunca um <code>migrate</code> simples, numa instalação nova - ver <a href="/clearance-docs/pt/guide/installation.html">Instalação</a>.</li></ul><h2 id="relacionado" tabindex="-1">Relacionado <a class="header-anchor" href="#relacionado" aria-label="Permalink to &quot;Relacionado&quot;">​</a></h2><ul><li><a href="/clearance-docs/pt/guide/architecture.html">Arquitetura</a> - precedência de resolução e o esquema <code>clr_*</code></li><li><a href="/clearance-docs/pt/features/roles.html">Papéis</a> - papéis-teto em profundidade</li><li><a href="/clearance-docs/pt/features/users.html">Utilizadores</a> - o teto de privilégio na atribuição de papéis/permissões</li><li><a href="/clearance-docs/pt/features/super-admin.html">Super Admin</a> - bypass da Gate e deteção de aliases</li></ul>',24)])])}const h=a(d,[["render",i]]);export{m as __pageData,h as default};
